import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.BQ1gajhD.js";const m=JSON.parse('{"title":"北京名胜古迹","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/index.md","filePath":"landmarks/index.md","lastUpdated":1784773307000}'),n={name:"landmarks/index.md"};function t(o,a,s,h,g,d){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="北京名胜古迹" tabindex="-1">北京名胜古迹 <a class="header-anchor" href="#北京名胜古迹" aria-label="Permalink to &quot;北京名胜古迹&quot;">​</a></h1><blockquote><p>&quot;千年帝都，古迹如云。&quot;</p></blockquote><p>北京作为六朝古都，拥有丰富的历史文化遗产。从皇家宫殿到万里长城，从祭天圣地到园林杰作，每一处古迹都诉说着中华文明的辉煌。</p><h2 id="皇家建筑" tabindex="-1">皇家建筑 <a class="header-anchor" href="#皇家建筑" aria-label="Permalink to &quot;皇家建筑&quot;">​</a></h2><h3 id="故宫博物院" tabindex="-1"><a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院</a> <a class="header-anchor" href="#故宫博物院" aria-label="Permalink to &quot;[故宫博物院](/landmarks/forbidden-city/)&quot;">​</a></h3><p>世界最大宫殿建筑群，明清两代皇宫，世界文化遗产。</p><ul><li><strong>门票</strong>：旺季60元，淡季40元</li><li><strong>建议时长</strong>：半天至一天</li><li><strong>看点</strong>：太和殿、乾清宫、御花园、珍宝馆</li></ul><p>🔍 <strong>子景点</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/wumen.html">午门</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/taihe-dian.html">太和殿</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/zhonghe-dian.html">中和殿</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/baohe-dian.html">保和殿</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/qianqing-gong.html">乾清宫</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/jiaotai-dian.html">交泰殿</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/kunning-gong.html">坤宁宫</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/yuhua-garden.html">御花园</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/zhenbao-guan.html">珍宝馆</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/zhongbiao-guan.html">钟表馆</a> · <a href="/beijing-travel-guide/landmarks/forbidden-city/jiulong-bi.html">九龙壁</a></p><h3 id="天坛" tabindex="-1"><a href="/beijing-travel-guide/landmarks/temple-of-heaven/">天坛</a> <a class="header-anchor" href="#天坛" aria-label="Permalink to &quot;[天坛](/landmarks/temple-of-heaven/)&quot;">​</a></h3><p>明清皇帝祭天祈谷之地，世界文化遗产。</p><ul><li><strong>门票</strong>：联票28元</li><li><strong>建议时长</strong>：3-4小时</li><li><strong>看点</strong>：祈年殿、回音壁、圜丘坛</li></ul><p>🔍 <strong>子景点</strong>：<a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">祈年殿</a> · <a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a> · <a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">皇穹宇与回音壁</a> · <a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a> · <a href="/beijing-travel-guide/landmarks/temple-of-heaven/zhai-gong.html">斋宫</a> · <a href="/beijing-travel-guide/landmarks/temple-of-heaven/shenyue-shu.html">神乐署</a></p><h3 id="颐和园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园</a> <a class="header-anchor" href="#颐和园" aria-label="Permalink to &quot;[颐和园](/landmarks/summer-palace/)&quot;">​</a></h3><p>中国古典园林巅峰之作，世界文化遗产。</p><ul><li><strong>门票</strong>：联票60元</li><li><strong>建议时长</strong>：半天至一天</li><li><strong>看点</strong>：佛香阁、长廊、十七孔桥、昆明湖</li></ul><p>🔍 <strong>子景点</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/renshou-dian.html">仁寿殿</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/dehe-yuan.html">德和园</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">昆明湖与十七孔桥</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/shifang.html">石舫</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/suzhou-street.html">苏州街</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/xiequ-yuan.html">谐趣园</a> · <a href="/beijing-travel-guide/landmarks/summer-palace/xidi-bridges.html">西堤六桥</a></p><h3 id="圆明园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园</a> <a class="header-anchor" href="#圆明园" aria-label="Permalink to &quot;[圆明园](/landmarks/yuanmingyuan/)&quot;">​</a></h3><p>&quot;万园之园&quot;遗址，爱国主义教育基地。</p><ul><li><strong>门票</strong>：联票25元</li><li><strong>建议时长</strong>：半天至一天</li><li><strong>看点</strong>：西洋楼遗址、大水法、十二生肖</li></ul><p>🔍 <strong>子景点</strong>：<a href="/beijing-travel-guide/landmarks/yuanmingyuan/dashuifa.html">大水法</a> · <a href="/beijing-travel-guide/landmarks/yuanmingyuan/haiyan-tang.html">海晏堂与十二生肖兽首</a> · <a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼建筑群</a> · <a href="/beijing-travel-guide/landmarks/yuanmingyuan/fuhai.html">福海景区</a> · <a href="/beijing-travel-guide/landmarks/yuanmingyuan/qichun-yuan.html">绮春园</a> · <a href="/beijing-travel-guide/landmarks/yuanmingyuan/wenyuan-ge.html">文源阁</a></p><h3 id="北海公园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/beihai/">北海公园</a> <a class="header-anchor" href="#北海公园" aria-label="Permalink to &quot;[北海公园](/landmarks/beihai/)&quot;">​</a></h3><p>现存最古老皇家园林，白塔琼岛。</p><ul><li><strong>门票</strong>：联票20元</li><li><strong>建议时长</strong>：2-3小时</li><li><strong>看点</strong>：白塔、九龙壁、让我们荡起双桨</li></ul><p>🔍 <strong>子景点</strong>：<a href="/beijing-travel-guide/landmarks/beihai/baita.html">白塔与琼华岛</a> · <a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a> · <a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a> · <a href="/beijing-travel-guide/landmarks/beihai/tuancheng.html">团城</a> · <a href="/beijing-travel-guide/landmarks/beihai/jingxinzhai.html">静心斋</a> · <a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a></p><h3 id="景山公园" tabindex="-1"><a href="/beijing-travel-guide/landmarks/jingshan/">景山公园</a> <a class="header-anchor" href="#景山公园" aria-label="Permalink to &quot;[景山公园](/landmarks/jingshan/)&quot;">​</a></h3><p>北京内城制高点，俯瞰紫禁城最佳位置。</p><ul><li><strong>门票</strong>：2元</li><li><strong>建议时长</strong>：1-2小时</li><li><strong>看点</strong>：万春亭、崇祯自缢处</li></ul><h2 id="长城" tabindex="-1">长城 <a class="header-anchor" href="#长城" aria-label="Permalink to &quot;长城&quot;">​</a></h2><h3 id="八达岭长城" tabindex="-1"><a href="/beijing-travel-guide/landmarks/badaling/">八达岭长城</a> <a class="header-anchor" href="#八达岭长城" aria-label="Permalink to &quot;[八达岭长城](/landmarks/badaling/)&quot;">​</a></h3><p>万里长城精华段，最早开放的长城。</p><ul><li><strong>门票</strong>：40元</li><li><strong>建议时长</strong>：3-4小时</li><li><strong>看点</strong>：北八楼、好汉坡、关城</li></ul><p>🔍 <strong>子景点</strong>：<a href="/beijing-travel-guide/landmarks/badaling/beibalou.html">北八楼与好汉坡</a> · <a href="/beijing-travel-guide/landmarks/badaling/guancheng.html">关城与城门</a> · <a href="/beijing-travel-guide/landmarks/badaling/dilou.html">敌楼与城墙</a> · <a href="/beijing-travel-guide/landmarks/badaling/wangjingshi.html">望京石与历史遗迹</a> · <a href="/beijing-travel-guide/landmarks/badaling/changcheng-museum.html">中国长城博物馆</a></p><h3 id="慕田峪长城" tabindex="-1"><a href="/beijing-travel-guide/landmarks/mutianyu.html">慕田峪长城</a> <a class="header-anchor" href="#慕田峪长城" aria-label="Permalink to &quot;[慕田峪长城](/landmarks/mutianyu)&quot;">​</a></h3><p>植被覆盖率最高，风景秀丽。</p><ul><li><strong>门票</strong>：40元</li><li><strong>建议时长</strong>：4-5小时</li><li><strong>看点</strong>：滑道、缆车、野长城</li></ul><h3 id="司马台长城" tabindex="-1"><a href="/beijing-travel-guide/landmarks/simatai.html">司马台长城</a> <a class="header-anchor" href="#司马台长城" aria-label="Permalink to &quot;[司马台长城](/landmarks/simatai)&quot;">​</a></h3><p>保存最原始，夜景独特。</p><ul><li><strong>门票</strong>：40元</li><li><strong>建议时长</strong>：半天</li><li><strong>看点</strong>：夜游长城、古北水镇</li></ul><h3 id="居庸关" tabindex="-1"><a href="/beijing-travel-guide/landmarks/juyongguan.html">居庸关</a> <a class="header-anchor" href="#居庸关" aria-label="Permalink to &quot;[居庸关](/landmarks/juyongguan)&quot;">​</a></h3><p>&quot;天下第一雄关&quot;，云台石刻。</p><ul><li><strong>门票</strong>：35元</li><li><strong>建议时长</strong>：2-3小时</li><li><strong>看点</strong>：云台、关城、云台石刻</li></ul><h2 id="胡同街区" tabindex="-1">胡同街区 <a class="header-anchor" href="#胡同街区" aria-label="Permalink to &quot;胡同街区&quot;">​</a></h2><h3 id="什刹海" tabindex="-1"><a href="/beijing-travel-guide/landmarks/shichahai.html">什刹海</a> <a class="header-anchor" href="#什刹海" aria-label="Permalink to &quot;[什刹海](/landmarks/shichahai)&quot;">​</a></h3><p>老北京水乡，胡同文化的代表。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：前海、后海、银锭桥、恭王府</li><li><strong>最佳时间</strong>：傍晚、夜晚</li></ul><h3 id="南锣鼓巷" tabindex="-1"><a href="/beijing-travel-guide/landmarks/nanluoguxiang.html">南锣鼓巷</a> <a class="header-anchor" href="#南锣鼓巷" aria-label="Permalink to &quot;[南锣鼓巷](/landmarks/nanluoguxiang)&quot;">​</a></h3><p>网红胡同，文艺与市井的融合。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：鱼骨状胡同、特色小店、名人故居</li><li><strong>最佳时间</strong>：工作日</li></ul><h3 id="前门大街" tabindex="-1"><a href="/beijing-travel-guide/landmarks/qianmen.html">前门大街</a> <a class="header-anchor" href="#前门大街" aria-label="Permalink to &quot;[前门大街](/landmarks/qianmen)&quot;">​</a></h3><p>老北京商业街，百年老字号。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：正阳门、铛铛车、老字号</li></ul><h3 id="大栅栏" tabindex="-1"><a href="/beijing-travel-guide/landmarks/dashilan.html">大栅栏</a> <a class="header-anchor" href="#大栅栏" aria-label="Permalink to &quot;[大栅栏](/landmarks/dashilan)&quot;">​</a></h3><p>百年商街，老北京的商业记忆。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：瑞蚨祥、内联升、同仁堂等老字号</li></ul><h3 id="琉璃厂" tabindex="-1"><a href="/beijing-travel-guide/landmarks/liulichang.html">琉璃厂</a> <a class="header-anchor" href="#琉璃厂" aria-label="Permalink to &quot;[琉璃厂](/landmarks/liulichang)&quot;">​</a></h3><p>传统文化街，文房四宝聚集地。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：古籍、字画、文房四宝</li></ul><h3 id="天桥" tabindex="-1"><a href="/beijing-travel-guide/landmarks/tianqiao.html">天桥</a> <a class="header-anchor" href="#天桥" aria-label="Permalink to &quot;[天桥](/landmarks/tianqiao)&quot;">​</a></h3><p>老北京民俗文化发源地。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：天桥剧场、民间艺术、传统曲艺</li></ul><h2 id="古城遗迹" tabindex="-1">古城遗迹 <a class="header-anchor" href="#古城遗迹" aria-label="Permalink to &quot;古城遗迹&quot;">​</a></h2><h3 id="明城墙遗址" tabindex="-1"><a href="/beijing-travel-guide/landmarks/city-wall.html">明城墙遗址</a> <a class="header-anchor" href="#明城墙遗址" aria-label="Permalink to &quot;[明城墙遗址](/landmarks/city-wall)&quot;">​</a></h3><p>北京仅存的一段明城墙。</p><ul><li><strong>门票</strong>：10元</li><li><strong>看点</strong>：东南角楼、城墙遗址</li></ul><h3 id="正阳门-箭楼" tabindex="-1"><a href="/beijing-travel-guide/landmarks/zhengyangmen.html">正阳门（箭楼）</a> <a class="header-anchor" href="#正阳门-箭楼" aria-label="Permalink to &quot;[正阳门（箭楼）](/landmarks/zhengyangmen)&quot;">​</a></h3><p>国门第一楼，守望京城六百年。</p><ul><li><strong>门票</strong>：免费（需预约）</li><li><strong>看点</strong>：城楼、箭楼、中轴线文化</li></ul><h3 id="钟鼓楼" tabindex="-1"><a href="/beijing-travel-guide/landmarks/drum-tower.html">钟鼓楼</a> <a class="header-anchor" href="#钟鼓楼" aria-label="Permalink to &quot;[钟鼓楼](/landmarks/drum-tower)&quot;">​</a></h3><p>古代报时中心，老北京地标。</p><ul><li><strong>门票</strong>：联票30元</li><li><strong>看点</strong>：鼓楼、钟楼、击鼓表演</li></ul><h3 id="恭王府" tabindex="-1"><a href="/beijing-travel-guide/landmarks/gongwangfu.html">恭王府</a> <a class="header-anchor" href="#恭王府" aria-label="Permalink to &quot;[恭王府](/landmarks/gongwangfu)&quot;">​</a></h3><p>清代最大王府，&quot;一座恭王府，半部清代史&quot;。</p><ul><li><strong>门票</strong>：40元</li><li><strong>看点</strong>：西洋门、大戏楼、福字碑</li></ul><h3 id="国子监与孔庙" tabindex="-1"><a href="/beijing-travel-guide/landmarks/guozijian.html">国子监与孔庙</a> <a class="header-anchor" href="#国子监与孔庙" aria-label="Permalink to &quot;[国子监与孔庙](/landmarks/guozijian)&quot;">​</a></h3><p>中国古代最高学府，祭祀孔子的场所。</p><ul><li><strong>门票</strong>：30元</li><li><strong>看点</strong>：辟雍殿、大成殿、十三经碑林</li></ul><h2 id="现代地标" tabindex="-1">现代地标 <a class="header-anchor" href="#现代地标" aria-label="Permalink to &quot;现代地标&quot;">​</a></h2><h3 id="鸟巢与水立方" tabindex="-1"><a href="/beijing-travel-guide/landmarks/niaochao.html">鸟巢与水立方</a> <a class="header-anchor" href="#鸟巢与水立方" aria-label="Permalink to &quot;[鸟巢与水立方](/landmarks/niaochao)&quot;">​</a></h3><p>2008年奥运标志，钢铁与水的建筑奇观。</p><ul><li><strong>门票</strong>：鸟巢50元，水立方30元</li><li><strong>看点</strong>：鸟巢钢结构、水立方气泡膜、夜景灯光</li><li><strong>最佳时间</strong>：傍晚、夜晚</li></ul><h3 id="国家大剧院" tabindex="-1"><a href="/beijing-travel-guide/landmarks/national-theatre.html">国家大剧院</a> <a class="header-anchor" href="#国家大剧院" aria-label="Permalink to &quot;[国家大剧院](/landmarks/national-theatre)&quot;">​</a></h3><p>&quot;水上明珠&quot;，中国最高表演艺术殿堂。</p><ul><li><strong>门票</strong>：参观30元</li><li><strong>看点</strong>：巨蛋造型、水下走廊、歌剧演出</li><li><strong>最佳时间</strong>：演出日</li></ul><h3 id="_798艺术区" tabindex="-1"><a href="/beijing-travel-guide/landmarks/798-art-zone.html">798艺术区</a> <a class="header-anchor" href="#_798艺术区" aria-label="Permalink to &quot;[798艺术区](/landmarks/798-art-zone)&quot;">​</a></h3><p>中国当代艺术的摇篮，老厂房里的艺术梦想。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：画廊、艺术家工作室、创意市集</li><li><strong>最佳时间</strong>：工作日</li></ul><h2 id="文化体验" tabindex="-1">文化体验 <a class="header-anchor" href="#文化体验" aria-label="Permalink to &quot;文化体验&quot;">​</a></h2><h3 id="老舍茶馆" tabindex="-1"><a href="/beijing-travel-guide/landmarks/lao-she-teahouse.html">老舍茶馆</a> <a class="header-anchor" href="#老舍茶馆" aria-label="Permalink to &quot;[老舍茶馆](/landmarks/lao-she-teahouse)&quot;">​</a></h3><p>京味文化体验，品茶听曲。</p><ul><li><strong>门票</strong>：参观免费，演出80-300元</li><li><strong>看点</strong>：茶艺表演、京剧、相声、评书</li><li><strong>最佳时间</strong>：演出日</li></ul><h3 id="潘家园旧货市场" tabindex="-1"><a href="/beijing-travel-guide/landmarks/panjiayuan.html">潘家园旧货市场</a> <a class="header-anchor" href="#潘家园旧货市场" aria-label="Permalink to &quot;[潘家园旧货市场](/landmarks/panjiayuan)&quot;">​</a></h3><p>淘宝者的天堂，老物件的博物馆。</p><ul><li><strong>门票</strong>：免费</li><li><strong>看点</strong>：古玩、旧货、民间工艺品</li><li><strong>最佳时间</strong>：周末</li></ul><h2 id="游览建议" tabindex="-1">游览建议 <a class="header-anchor" href="#游览建议" aria-label="Permalink to &quot;游览建议&quot;">​</a></h2><h3 id="经典三日游" tabindex="-1">经典三日游 <a class="header-anchor" href="#经典三日游" aria-label="Permalink to &quot;经典三日游&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">天数</th><th style="text-align:left;">上午</th><th style="text-align:left;">下午</th><th style="text-align:left;">晚上</th></tr></thead><tbody><tr><td style="text-align:center;">Day1</td><td style="text-align:left;">天安门广场</td><td style="text-align:left;">故宫博物院</td><td style="text-align:left;">王府井</td></tr><tr><td style="text-align:center;">Day2</td><td style="text-align:left;">八达岭长城</td><td style="text-align:left;">明十三陵</td><td style="text-align:left;">后海酒吧街</td></tr><tr><td style="text-align:center;">Day3</td><td style="text-align:left;">天坛</td><td style="text-align:left;">颐和园</td><td style="text-align:left;">前门大街</td></tr></tbody></table><h3 id="门票预约须知" tabindex="-1">门票预约须知 <a class="header-anchor" href="#门票预约须知" aria-label="Permalink to &quot;门票预约须知&quot;">​</a></h3><ol><li><strong>故宫</strong>：必须提前7天预约，现场不售票</li><li><strong>国博</strong>：提前1-7天预约，周一闭馆</li><li><strong>长城</strong>：建议提前预约，旺季限流</li><li><strong>颐和园/天坛</strong>：可现场购票，但旺季建议预约</li></ol><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li>穿舒适的鞋子，每天步行量很大</li><li>带足饮水，景区内水较贵</li><li>注意防晒，夏季北京紫外线强</li><li>保管好证件，很多景点需刷身份证</li></ul><hr><p><strong>💡 提示</strong>：点击景点名称查看详细介绍和攻略</p>',102)])])}const b=e(n,[["render",t]]);export{m as __pageData,b as default};
